import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';  // Adăugăm Router pentru navigare
import Sidebar from './components/Sidebar';
import Zoom from './components/Zoom';  // Importăm componenta Zoom
import './App.css';

const App = () => {
  const [activeComponent, setActiveComponent] = useState(null);

  return (
    <Router>
      <div className="App">
        <Sidebar activeComponent={activeComponent} setActiveComponent={setActiveComponent} />

        {/* Adăugăm rutele doar pentru Zoom */}
        <Routes>
          {/* Ruta principală poate afișa altceva */}
          <Route path="/" element={<div>Welcome to My Shortcuts</div>} /> 
          {/* Navigare către componenta Zoom */}
          <Route path="/zoom" element={<Zoom />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
